import{f as e,o as d,c as a,a2 as s}from"./chunks/framework.Ccw_j35p.js";const u=JSON.parse('{"title":"Linux 学习路径与工具生态","description":"","frontmatter":{},"headers":[],"relativePath":"devops/linux/index.md","filePath":"devops/linux/index.md","lastUpdated":1780925008000}'),n={name:"devops/linux/index.md"};function o(c,t,r,l,i,p){return d(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="linux-学习路径与工具生态" tabindex="-1">Linux 学习路径与工具生态 <a class="header-anchor" href="#linux-学习路径与工具生态" aria-label="Permalink to &quot;Linux 学习路径与工具生态&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>考点</th><th>频率</th><th>难度</th><th>考察方式</th></tr></thead><tbody><tr><td>文件系统层次结构（FHS）</td><td>⭐⭐⭐⭐</td><td>⭐⭐</td><td>各目录用途，跨发行版差异</td></tr><tr><td>常用工具分类与选择</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐</td><td>场景题：给你一个排障场景，你用哪些工具/命令</td></tr><tr><td>包管理差异（apt/yum）</td><td>⭐⭐⭐</td><td>⭐⭐</td><td>生产环境常用操作</td></tr><tr><td>Linux 内核版本与发行版关系</td><td>⭐⭐⭐</td><td>⭐⭐</td><td>主流发行版选型建议</td></tr><tr><td>Linux 学习路径规划</td><td>⭐⭐⭐</td><td>⭐⭐</td><td>开放性问题，考察知识体系完整性</td></tr></tbody></table><hr><h2 id="一、文件系统层次结构-fhs" tabindex="-1">一、文件系统层次结构（FHS） <a class="header-anchor" href="#一、文件系统层次结构-fhs" aria-label="Permalink to &quot;一、文件系统层次结构（FHS）&quot;">​</a></h2><p>Filesystem Hierarchy Standard 定义了 Linux 目录结构的标准。面试中常问&quot;某某文件放在哪个目录&quot;，本质是考察你对系统运行的理解。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/               # 根目录，一切文件的起点</span></span>
<span class="line"><span>├── /bin        # 基本用户命令（ls、cp、cat 等），软链接到 /usr/bin</span></span>
<span class="line"><span>├── /sbin       # 系统管理命令（fdisk、mkfs、iptables），软链接到 /usr/sbin</span></span>
<span class="line"><span>├── /boot       # 内核镜像 vmlinuz、initramfs、grub 配置</span></span>
<span class="line"><span>├── /dev        # 设备文件（sda、tty、null、random）</span></span>
<span class="line"><span>├── /etc        # 系统级配置文件（ssh、nginx、sysctl.conf）</span></span>
<span class="line"><span>├── /home       # 普通用户家目录</span></span>
<span class="line"><span>├── /root       # root 用户家目录</span></span>
<span class="line"><span>├── /lib        # 共享库和内核模块，软链接到 /usr/lib</span></span>
<span class="line"><span>├── /media      # 可移动介质挂载点（U盘、CD-ROM）</span></span>
<span class="line"><span>├── /mnt        # 临时手动挂载点</span></span>
<span class="line"><span>├── /opt        # 第三方软件安装目录（如 /opt/jdk、/opt/nginx）</span></span>
<span class="line"><span>├── /proc       # 虚拟文件系统，内核和进程信息（cpuinfo、meminfo、PID目录）</span></span>
<span class="line"><span>├── /sys        # 虚拟文件系统，设备、驱动、内核参数（比 /proc 更结构化）</span></span>
<span class="line"><span>├── /run        # 系统启动以来的运行时数据（tmpfs），PID文件、socket文件</span></span>
<span class="line"><span>├── /srv        # 服务数据目录（如 /srv/www）</span></span>
<span class="line"><span>├── /tmp        # 临时文件，重启可能被清理（通常为 tmpfs）</span></span>
<span class="line"><span>├── /usr        # 用户级程序和数据（Unix System Resources）</span></span>
<span class="line"><span>│   ├── /usr/bin</span></span>
<span class="line"><span>│   ├── /usr/sbin</span></span>
<span class="line"><span>│   ├── /usr/lib</span></span>
<span class="line"><span>│   ├── /usr/local  # 本地编译安装的软件</span></span>
<span class="line"><span>│   └── /usr/share  # 架构无关数据（文档、man page）</span></span>
<span class="line"><span>└── /var        # 可变数据（日志、缓存、邮件队列、数据库文件）</span></span>
<span class="line"><span>    ├── /var/log     # 日志文件（messages、syslog、nginx/）</span></span>
<span class="line"><span>    └── /var/lib     # 应用程序状态数据（mysql、docker）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">排障要点</p><ul><li><code>/proc</code> 和 <code>/sys</code> 是排障黄金信息来源。比如 <code>/proc/PID/fd</code> 可以看到进程打开的文件描述符，<code>/proc/sys/</code> 可以动态修改内核参数。</li><li><code>/var/log</code> 下日志满了导致磁盘满，是生产环境最常见的故障之一。</li></ul></div><div class="danger custom-block"><p class="custom-block-title">常见陷阱</p><p>不要随意删除 <code>/tmp</code> 下的文件如果它是某个进程正在使用的 socket 文件。<code>/tmp</code> 下可能有 systemd 的私有 tmp 目录（<code>/tmp/systemd-private-*</code>）。</p></div><hr><h2 id="二、常用工具分类" tabindex="-1">二、常用工具分类 <a class="header-anchor" href="#二、常用工具分类" aria-label="Permalink to &quot;二、常用工具分类&quot;">​</a></h2><p>按排障场景组织工具远比按字母表记忆有效。以下是高级工程师常用的分类体系：</p><h3 id="_2-1-cpu-与进程分析" tabindex="-1">2.1 CPU 与进程分析 <a class="header-anchor" href="#_2-1-cpu-与进程分析" aria-label="Permalink to &quot;2.1 CPU 与进程分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>场景</th></tr></thead><tbody><tr><td><code>top</code> / <code>htop</code></td><td>实时进程监控</td><td>快速定位 CPU 占用高的进程</td></tr><tr><td><code>ps</code></td><td>进程快照</td><td>查看特定进程详情</td></tr><tr><td><code>pidstat</code></td><td>进程级 CPU 统计</td><td>精细化分析，支持历史数据</td></tr><tr><td><code>mpstat</code></td><td>CPU 各核心统计</td><td>判断是否单核瓶颈</td></tr><tr><td><code>strace</code></td><td>跟踪系统调用</td><td>分析进程卡在哪个系统调用</td></tr><tr><td><code>perf</code></td><td>性能采样</td><td>火焰图分析、热点函数定位</td></tr></tbody></table><h3 id="_2-2-内存分析" tabindex="-1">2.2 内存分析 <a class="header-anchor" href="#_2-2-内存分析" aria-label="Permalink to &quot;2.2 内存分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>场景</th></tr></thead><tbody><tr><td><code>free</code></td><td>内存概览</td><td>快速看 used/free/buffer/cache</td></tr><tr><td><code>vmstat</code></td><td>虚拟内存统计</td><td>整体内存和 swap 活动</td></tr><tr><td><code>pmap</code></td><td>进程内存映射</td><td>查看进程详细内存分布</td></tr><tr><td><code>smem</code></td><td>物理内存统计</td><td>更准确的 PSS/USS 统计</td></tr><tr><td><code>/proc/PID/smaps</code></td><td>内存段详情</td><td>排查内存泄漏</td></tr></tbody></table><h3 id="_2-3-磁盘与-io" tabindex="-1">2.3 磁盘与 IO <a class="header-anchor" href="#_2-3-磁盘与-io" aria-label="Permalink to &quot;2.3 磁盘与 IO&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>场景</th></tr></thead><tbody><tr><td><code>df</code> / <code>du</code></td><td>磁盘空间/目录大小</td><td>磁盘满了先查什么</td></tr><tr><td><code>iostat</code></td><td>IO 统计</td><td>磁盘性能瓶颈</td></tr><tr><td><code>iotop</code></td><td>进程级 IO 监控</td><td>哪个进程在疯狂读写</td></tr><tr><td><code>lsof</code></td><td>列出打开的文件</td><td>文件被谁占用、端口被谁监听</td></tr><tr><td><code>fdisk</code> / <code>lsblk</code></td><td>磁盘分区</td><td>磁盘扩容前准备</td></tr></tbody></table><h3 id="_2-4-网络排障" tabindex="-1">2.4 网络排障 <a class="header-anchor" href="#_2-4-网络排障" aria-label="Permalink to &quot;2.4 网络排障&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>场景</th></tr></thead><tbody><tr><td><code>ss</code></td><td>Socket 统计（替代 netstat）</td><td>查看监听端口、连接状态</td></tr><tr><td><code>tcpdump</code></td><td>抓包分析</td><td>网络不通、响应慢</td></tr><tr><td><code>curl</code> / <code>wget</code></td><td>HTTP 请求测试</td><td>接口联通性验证</td></tr><tr><td><code>iptables</code> / <code>nftables</code></td><td>防火墙规则</td><td>排查防火墙拦截</td></tr><tr><td><code>mtr</code></td><td>路由追踪+丢包率</td><td>网络质量分析</td></tr></tbody></table><h3 id="_2-5-综合排障" tabindex="-1">2.5 综合排障 <a class="header-anchor" href="#_2-5-综合排障" aria-label="Permalink to &quot;2.5 综合排障&quot;">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>用途</th><th>场景</th></tr></thead><tbody><tr><td><code>dmesg</code></td><td>内核日志</td><td>OOM killer、硬件错误</td></tr><tr><td><code>journalctl</code></td><td>systemd 日志</td><td>服务启动失败原因</td></tr><tr><td><code>sar</code></td><td>系统活动报告</td><td>回溯历史性能数据</td></tr><tr><td><code>bcc</code> / <code>bpftrace</code></td><td>动态追踪</td><td>复杂问题深入分析</td></tr></tbody></table><hr><h2 id="三、学习路径建议" tabindex="-1">三、学习路径建议 <a class="header-anchor" href="#三、学习路径建议" aria-label="Permalink to &quot;三、学习路径建议&quot;">​</a></h2><h3 id="阶段一-基础操作-1-2-周" tabindex="-1">阶段一：基础操作（1-2 周） <a class="header-anchor" href="#阶段一-基础操作-1-2-周" aria-label="Permalink to &quot;阶段一：基础操作（1-2 周）&quot;">​</a></h3><ul><li>文件和目录操作：<code>ls</code>、<code>cd</code>、<code>cp</code>、<code>mv</code>、<code>rm</code>、<code>find</code></li><li>文件查看和编辑：<code>cat</code>、<code>less</code>、<code>tail</code>、<code>vim</code>、<code>grep</code></li><li>权限管理：<code>chmod</code>、<code>chown</code>、<code>sudo</code></li><li>管道与重定向：<code>|</code>、<code>&gt;</code>、<code>&gt;&gt;</code>、<code>&lt;</code></li></ul><h3 id="阶段二-系统管理-2-3-周" tabindex="-1">阶段二：系统管理（2-3 周） <a class="header-anchor" href="#阶段二-系统管理-2-3-周" aria-label="Permalink to &quot;阶段二：系统管理（2-3 周）&quot;">​</a></h3><ul><li>进程管理：<code>ps</code>、<code>top</code>、<code>kill</code>、<code>systemctl</code></li><li>磁盘管理：<code>df</code>、<code>du</code>、<code>mount</code>、<code>fdisk</code></li><li>网络配置：<code>ip</code>、<code>ss</code>、<code>ping</code>、<code>curl</code></li><li>用户和组：<code>useradd</code>、<code>usermod</code>、<code>groupadd</code></li></ul><h3 id="阶段三-shell-编程-1-2-周" tabindex="-1">阶段三：Shell 编程（1-2 周） <a class="header-anchor" href="#阶段三-shell-编程-1-2-周" aria-label="Permalink to &quot;阶段三：Shell 编程（1-2 周）&quot;">​</a></h3><ul><li>变量、条件判断、循环</li><li>函数、参数传递</li><li>awk/sed 文本处理</li><li>编写自动化运维脚本</li></ul><h3 id="阶段四-性能与排障-持续" tabindex="-1">阶段四：性能与排障（持续） <a class="header-anchor" href="#阶段四-性能与排障-持续" aria-label="Permalink to &quot;阶段四：性能与排障（持续）&quot;">​</a></h3><ul><li>性能分析工具链：<code>perf</code>、<code>bcc</code>、<code>strace</code></li><li>内核参数调优：<code>sysctl</code>、<code>/proc/sys/</code></li><li>日志分析：<code>journalctl</code>、<code>/var/log</code></li><li>网络排障：<code>tcpdump</code>、<code>ss</code>、<code>iptables</code></li></ul><div class="tip custom-block"><p class="custom-block-title">实战建议</p><p>不要只看不练。建议在本地虚拟机或云服务器上搭建一个完整的 LAMP/LNMP 环境，然后故意制造故障（如改错配置、填满磁盘、耗尽内存），用工具链去排查和修复。</p></div><hr><h2 id="四、与相关模块的交叉引用" tabindex="-1">四、与相关模块的交叉引用 <a class="header-anchor" href="#四、与相关模块的交叉引用" aria-label="Permalink to &quot;四、与相关模块的交叉引用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识点</th><th>相关模块</th></tr></thead><tbody><tr><td>进程调度、上下文切换</td><td><a href="./../../operating-system/process-thread/">操作系统 - 进程与线程</a></td></tr><tr><td>内存管理、虚拟内存</td><td><a href="./../../operating-system/memory/">操作系统 - 内存管理</a></td></tr><tr><td>文件系统、inode、VFS</td><td><a href="./../../operating-system/filesystem/">操作系统 - 文件系统</a></td></tr><tr><td>IO 模型、select/epoll</td><td><a href="./../../operating-system/io/">操作系统 - IO模型</a></td></tr><tr><td>TCP 状态、三次握手</td><td><a href="./../../computer-network/transport/tcp">计算机网络 - 传输层</a></td></tr><tr><td>HTTP 协议、抓包分析</td><td><a href="./../../computer-network/application/http">计算机网络 - 应用层</a></td></tr></tbody></table><hr><h2 id="五、高频面试题" tabindex="-1">五、高频面试题 <a class="header-anchor" href="#五、高频面试题" aria-label="Permalink to &quot;五、高频面试题&quot;">​</a></h2><h3 id="q1-proc-和-sys-的区别是什么" tabindex="-1">Q1：/proc 和 /sys 的区别是什么？ <a class="header-anchor" href="#q1-proc-和-sys-的区别是什么" aria-label="Permalink to &quot;Q1：/proc 和 /sys 的区别是什么？&quot;">​</a></h3><p><strong>答案：</strong> <code>/proc</code> 是早期 Linux 的伪文件系统，最初设计为进程信息接口，后来混杂了内核参数（<code>/proc/sys/</code>）。<code>/sys</code> 是 2.6 内核引入的 sysfs，结构更清晰，专门用于导出设备、驱动、总线等内核对象信息。Linux 社区推荐新的内核接口使用 <code>/sys</code>，<code>/proc</code> 保留向后兼容。例如 CPU 信息：<code>/proc/cpuinfo</code> vs <code>/sys/devices/system/cpu/</code>。</p><h3 id="q2-linux-上如何查看一个进程打开了哪些文件" tabindex="-1">Q2：Linux 上如何查看一个进程打开了哪些文件？ <a class="header-anchor" href="#q2-linux-上如何查看一个进程打开了哪些文件" aria-label="Permalink to &quot;Q2：Linux 上如何查看一个进程打开了哪些文件？&quot;">​</a></h3><p><strong>答案：</strong> 使用 <code>lsof -p PID</code> 或 <code>ls -la /proc/PID/fd/</code>。后者更轻量，直接查看文件描述符目录下的软链接。<code>lsof</code> 功能更强大，可以按端口（<code>lsof -i :80</code>）、用户（<code>lsof -u root</code>）、文件（<code>lsof /var/log/messages</code>）过滤。</p><h3 id="q3-tmp-目录满了怎么办-能直接删吗" tabindex="-1">Q3：/tmp 目录满了怎么办？能直接删吗？ <a class="header-anchor" href="#q3-tmp-目录满了怎么办-能直接删吗" aria-label="Permalink to &quot;Q3：/tmp 目录满了怎么办？能直接删吗？&quot;">​</a></h3><p><strong>答案：</strong> 不能盲目删除。首先用 <code>du -sh /tmp/*</code> 找出大文件。然后检查是否有进程在使用这些文件（<code>lsof /tmp/xxx</code>）。如果有进程持有文件句柄，删除文件只是删除了目录项，inode 和数据块不会被释放，磁盘空间不会恢复。正确的做法是截断文件（<code>&gt; /tmp/largefile</code>）或找到并重启对应进程。</p><h3 id="q4-如何查看-linux-系统已运行了多久" tabindex="-1">Q4：如何查看 Linux 系统已运行了多久？ <a class="header-anchor" href="#q4-如何查看-linux-系统已运行了多久" aria-label="Permalink to &quot;Q4：如何查看 Linux 系统已运行了多久？&quot;">​</a></h3><p><strong>答案：</strong> <code>uptime</code> 命令，输出示例：<code>14:32:08 up 365 days, 4:15, 3 users, load average: 0.52, 0.38, 0.31</code>。它还显示当前时间、登录用户数和系统负载。<code>/proc/uptime</code> 文件包含两个数字：系统运行秒数和空闲秒数。</p><h3 id="q5-linux-发行版之间切换需要注意什么" tabindex="-1">Q5：Linux 发行版之间切换需要注意什么？ <a class="header-anchor" href="#q5-linux-发行版之间切换需要注意什么" aria-label="Permalink to &quot;Q5：Linux 发行版之间切换需要注意什么？&quot;">​</a></h3><p><strong>答案：</strong> 主要差异：包管理器（apt vs yum/dnf vs apk）、服务管理（systemd 是主流，但 Alpine 用 openrc）、默认配置路径（如 Nginx 配置在 /etc/nginx 基本一致，但日志路径可能不同）、SELinux（CentOS/RHEL 默认开启）vs AppArmor（Ubuntu 默认开启）、内核版本差异导致某些 bcc/eBPF 工具不可用。建议团队统一发行版，减少运维负担。</p><h3 id="q6-如何快速学习一个新的-linux-命令" tabindex="-1">Q6：如何快速学习一个新的 Linux 命令？ <a class="header-anchor" href="#q6-如何快速学习一个新的-linux-命令" aria-label="Permalink to &quot;Q6：如何快速学习一个新的 Linux 命令？&quot;">​</a></h3><p><strong>答案：</strong> 四步法：（1）<code>man command</code> 或 <code>command --help</code> 看概述和常用选项；（2）<code>tldr command</code>（需要安装 tldr 工具）看常见用例；（3）实际运行并观察输出；（4）阅读 <code>info command</code> 获取更深入的解释（如果 man page 不够详细）。不要试图记住所有参数，记住核心用法，复杂参数用 man 查即可。</p>`,50)])])}const b=e(n,[["render",o]]);export{u as __pageData,b as default};
